import vex

@vex.verify(
    checks=[
        vex.safety_check(
            categories=['hate_speech', 'violence'],
            threshold=0.1,  # Low threshold for voice
            context='voice_conversation'
        )
    ]
)
async def safe_voice_turn(audio_text: str, conversation_id: str) -> str:
    response = await client.chat.completions.create(
        messages=[{'role': 'user', 'content': audio_text}],
        conversation_id=conversation_id
    )
    return response.choices[0].message.content

@vex.verify(
    checks=[
        vex.schema_check('tool_response', WeatherToolResponse),
        vex.semantic_similarity_check(
            reference='conversation_history',
            threshold=0.75,
            description='Ensure response coherent with voice context'
        ),
        vex.custom_check('memory_relevance', validate_memory_associations)
    ]
)
async def coherent_voice_agent(audio_text: str, history: List[str]):
    context = await retrieve_context(client, 'session_123', audio_text)
    full_prompt = f"History: {' '.join(history[-3:])}\nContext: {' '.join(context)}\nUser: {audio_text}"

    response = await client.chat.completions.create(
        messages=[{'role': 'user', 'content': full_prompt}]
    )
    return {
        'response': response.choices[0].message.content,
        'used_context': context,
        'conversation_history': history
    }
